import { useState, useEffect, useCallback } from "react";
import { useSearchParams } from "react-router-dom";
import MapView from "../components/MapView";
import PlaceSidebar from "../components/PlaceSidebar";
import api from "../utils/api";
import { CATEGORY_OPTIONS } from "../utils/categories";
import { PinIcon } from "../components/UiIcons";

export default function HomePage() {
  const [params, setParams] = useSearchParams();
  const [places, setPlaces] = useState([]);
  const [loading, setLoading] = useState(true);
  const [userPos, setUserPos] = useState(null);
  const [mapCenter, setMapCenter] = useState(null);
  const [mapZoom, setMapZoom] = useState(13);
  // fixed search radius (km)
  const radius = 5;
  const [search, setSearch] = useState("");
  const [selectedId, setSelectedId] = useState("");
  const cat = params.get("category") || "all";

  const sortPlacesByDistance = (list) => {
    const arr = list || [];
    const hasDistance = arr.some((p) => typeof p.distance === "number");
    if (!hasDistance) return arr;
    return [...arr].sort(
      (a, b) => (a.distance ?? Infinity) - (b.distance ?? Infinity),
    );
  };

  const setPlacesAndScroll = (list) => {
    setPlaces(list);
    try {
      const el = document.getElementById("place-sidebar");
      if (el) el.scrollTop = 0;
    } catch (e) {
      // ignore
    }
  };

  const load = useCallback(async () => {
    setLoading(true);
    try {
      let data;
      if (userPos) {
        const [lat, lng] = userPos;
        const useRadius = cat === "resort" ? Math.max(radius, 100) : radius;
        const q = new URLSearchParams();
        q.set("lat", lat);
        q.set("lng", lng);
        q.set("radius", useRadius);
        if (cat !== "all") q.set("category", cat);
        if (search) q.set("search", search);
        const url = `/places/nearby?${q.toString()}`;
        ({ data } = await api.get(url));

        // fallback: if resort and nothing nearby, fetch all resorts
        if (
          cat === "resort" &&
          Array.isArray(data.data) &&
          data.data.length === 0
        ) {
          const { data: listData } = await api.get(`/places?category=resort`);
          data = listData;
          // if we have resorts but none nearby, center map to the first resort so markers are visible
          if (data.data?.[0]) {
            const first = data.data[0];
            setMapCenter([first.location.lat, first.location.lng]);
            setMapZoom(10);
            setSelectedId(first._id);
          }
        }
      } else {
        let url = "/places";
        const q = new URLSearchParams();
        if (cat !== "all") q.set("category", cat);
        if (search) q.set("search", search);
        if (q.toString()) url += "?" + q;
        ({ data } = await api.get(url));
      }
      setPlacesAndScroll(sortPlacesByDistance(data.data || []));
      console.log("[HomePage] loaded places:", (data.data || []).length, {
        cat,
        userPos,
      });

      if (!selectedId && data.data?.[0]) {
        setSelectedId(data.data[0]._id);
      }
    } catch {
      setPlaces([]);
    }
    setLoading(false);
  }, [cat, search, userPos, radius]);

  useEffect(() => {
    load();
  }, [load]);

  const getLocation = () => {
    navigator.geolocation?.getCurrentPosition(async (pos) => {
      const { latitude: lat, longitude: lng } = pos.coords;
      setUserPos([lat, lng]);
      setMapCenter([lat, lng]);
      setMapZoom(14);
      try {
        const useRadius = cat === "resort" ? Math.max(radius, 100) : radius;
        const { data } = await api.get(
          `/places/nearby?lat=${lat}&lng=${lng}&radius=${useRadius}${cat !== "all" ? `&category=${cat}` : ""}`,
        );
        setPlacesAndScroll(sortPlacesByDistance(data.data || []));
        if (data.data?.[0]) {
          setSelectedId(data.data[0]._id);
          // Do NOT change map center to the nearest place — keep focus on user marker
        } else if (cat === "resort") {
          // fallback to list all resorts if none nearby
          const { data: listData } = await api.get(`/places?category=resort`);
          setPlacesAndScroll(sortPlacesByDistance(listData.data || []));
          if (listData.data?.[0]) {
            setSelectedId(listData.data[0]._id);
            // center map on the first resort so it's visible
            setMapCenter([
              listData.data[0].location.lat,
              listData.data[0].location.lng,
            ]);
            setMapZoom(10);
          }
        }
      } catch {}
    });
  };

  useEffect(() => {
    getLocation();
  }, []); // eslint-disable-line

  // removed dynamic radius effect — radius is fixed

  const setCat = async (key) => {
    const next = new URLSearchParams(params);
    if (key === "all") next.delete("category");
    else next.set("category", key);
    setParams(next);

    // expand radius for resorts so remote ones are included
    const useRadius = key === "resort" ? Math.max(radius, 100) : radius;

    if (!userPos) {
      const filtered =
        key === "all" ? places : places.filter((p) => p.category === key);
      setPlacesAndScroll(sortPlacesByDistance(filtered));
      if (filtered[0]) {
        setSelectedId(filtered[0]._id);
        setMapCenter([filtered[0].location.lat, filtered[0].location.lng]);
        setMapZoom(15);
      }
      // scroll category button into view
      try {
        const btn = document.querySelector(`[data-cat="${key}"]`);
        btn?.scrollIntoView({
          behavior: "smooth",
          inline: "center",
          block: "nearest",
        });
      } catch (e) {}
      return;
    }

    try {
      const [lat, lng] = userPos;
      const { data } = await api.get(
        `/places/nearby?lat=${lat}&lng=${lng}&radius=${useRadius}${key !== "all" ? `&category=${key}` : ""}`,
      );
      setPlacesAndScroll(sortPlacesByDistance(data.data || []));

      if (data.data?.[0]) {
        setSelectedId(data.data[0]._id);
        setMapCenter([data.data[0].location.lat, data.data[0].location.lng]);
        setMapZoom(15);
      } else {
        setMapCenter([lat, lng]);
        setMapZoom(14);
      }
      // scroll category button into view
      try {
        const btn = document.querySelector(`[data-cat="${key}"]`);
        btn?.scrollIntoView({
          behavior: "smooth",
          inline: "center",
          block: "nearest",
        });
      } catch (e) {}

      // radius is fixed; do not update UI
    } catch {}
  };

  const selectPlace = (place) => {
    setSelectedId(place._id);
    setMapCenter([place.location.lat, place.location.lng]);
    setMapZoom(16);
    // Ensure user's current location marker is available when a place is selected
    if (!userPos) {
      navigator.geolocation?.getCurrentPosition(
        (pos) => {
          const { latitude: lat, longitude: lng } = pos.coords;
          setUserPos([lat, lng]);
        },
        () => {},
      );
    }
  };

  return (
    <div
      style={{
        height: "calc(100vh - 56px)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          padding: "10px 20px",
          background: "var(--bg)",
          borderBottom: "1px solid var(--border)",
          display: "flex",
          gap: 8,
          alignItems: "center",
          overflowX: "auto",
        }}
      >
        {CATEGORY_OPTIONS.map((c) => {
          const CategoryIcon = c.icon;
          return (
            <button
              key={c.value}
              data-cat={c.value}
              onClick={() => setCat(c.value)}
              style={{
                padding: "6px 16px",
                borderRadius: 20,
                fontSize: 13,
                fontWeight: 500,
                cursor: "pointer",
                border: "1px solid",
                whiteSpace: "nowrap",
                background: cat === c.value ? "var(--teal)" : "var(--card)",
                color: cat === c.value ? "#fff" : "var(--muted)",
                borderColor: cat === c.value ? "var(--teal)" : "var(--border)",
              }}
            >
              <span style={{ display: "inline-flex", marginRight: 6 }}>
                <CategoryIcon size={14} />
              </span>
              {c.label}
            </button>
          );
        })}

        <div
          style={{
            marginLeft: "auto",
            display: "flex",
            gap: 8,
            alignItems: "center",
          }}
        >
          <input
            placeholder="Хайх..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              padding: "6px 12px",
              background: "var(--card)",
              border: "1px solid var(--border)",
              borderRadius: 8,
              color: "var(--text)",
              fontSize: 13,
              width: 180,
            }}
          />

          {/* radius control removed */}

          <button
            onClick={getLocation}
            style={{
              padding: "6px 14px",
              background: "var(--blue)",
              color: "#fff",
              border: "none",
              borderRadius: 8,
              cursor: "pointer",
              fontSize: 13,
              whiteSpace: "nowrap",
            }}
          >
            <span style={{ display: "inline-flex", marginRight: 6 }}>
              <PinIcon size={14} />
            </span>
            Байршил
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        <div style={{ flex: 1, position: "relative" }}>
          <MapView
            businesses={places}
            userPos={userPos}
            center={mapCenter}
            zoom={mapZoom}
          />
        </div>

        <PlaceSidebar
          places={places}
          selectedId={selectedId}
          loading={loading}
          onSelect={selectPlace}
        />
      </div>
    </div>
  );
}
